    try {
      _setLoading(true);
      _clearError();

      // Capture GPS location on inspection start
      GpsCoordinates? gpsLocation;
      try {
        gpsLocation = await GpsService.instance.captureGpsForInspection();
        if (gpsLocation != null) {
          debugPrint('[InspectionProvider] GPS captured: ${gpsLocation.latitude}, ${gpsLocation.longitude}');
        } else {
          debugPrint('[InspectionProvider] GPS capture failed, inspection will proceed without GPS');
        }
      } catch (e) {
        debugPrint('[InspectionProvider] GPS capture error (non-fatal): $e');
        // GPS is optional, so we continue even if it fails
      }

      final inspection = Inspection(
        id: _uuid.v4(),
        templateId: templateId,
        templateVersionId: templateVersionId,
        gpsLocation: gpsLocation, // Store GPS coordinates with inspection
      );

      _currentInspection = inspection;
      _currentTemplate = template;
      _formData.clear();
      _fieldUiStates.clear();

      // Initialize field UI states
      for (final section in template.sections) {
        for (final field in section.fields) {
          _fieldUiStates[field.id] = FieldUiState(
            visible: true,
            disabled: false,
            required: field.validation?.required ?? false,
          );
        }
      }

      await _autoFillEquipmentData();

      // Save to database
      await _saveInspectionToDb(inspection);

      notifyListeners();
    } catch (e) {
      _setError('Failed to start inspection: ${e.toString()}');
      rethrow;
    } finally {
      _setLoading(false);
    }
  }

