/// Inspection List State - Manages inspection list business logic
/// Implements ChangeNotifier for reactive state management
/// Shared across all device-specific inspection list views
library;

import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import 'package:go_router/go_router.dart';
import '../../../../navigation/app_router.dart';
import '../../../../providers/inspection_provider.dart' as db;

/// Inspection data model
class Inspection {
  final String id;
  final String title;
  final String status;
  final DateTime lastModified;
  final String location;
  final String equipmentType;
  final double progress;

  const Inspection({
    required this.id,
    required this.title,
    required this.status,
    required this.lastModified,
    required this.location,
    required this.equipmentType,
    required this.progress,
  });
}

/// Inspection List screen state management using ChangeNotifier pattern
class InspectionListState extends ChangeNotifier {
  // Service locator pattern for state access
  static InspectionListState s(BuildContext context, [bool listen = false]) =>
      Provider.of<InspectionListState>(context, listen: listen);

  // State variables
  bool _isLoading = false;
  String? _errorMessage;
  List<Inspection> _inspections = [];
  String _searchQuery = '';
  String _filterStatus = 'All';

  // Getters
  bool get isLoading => _isLoading;
  String? get errorMessage => _errorMessage;
  List<Inspection> get inspections => _filteredInspections;
  String get searchQuery => _searchQuery;
  String get filterStatus => _filterStatus;

  // Available filter options
  List<String> get filterOptions => ['All', 'In Progress', 'Completed', 'Scheduled', 'Under Review'];

  // Filtered inspections based on search and filter
  List<Inspection> get _filteredInspections {
    var filtered = _inspections;

    // Apply status filter
    if (_filterStatus != 'All') {
      filtered = filtered.where((inspection) => inspection.status == _filterStatus).toList();
    }

    // Apply search filter
    if (_searchQuery.isNotEmpty) {
      filtered = filtered.where((inspection) =>
          inspection.title.toLowerCase().contains(_searchQuery.toLowerCase()) ||
          inspection.location.toLowerCase().contains(_searchQuery.toLowerCase()) ||
          inspection.equipmentType.toLowerCase().contains(_searchQuery.toLowerCase())).toList();
    }

    return filtered;
  }

  /// Initialize state and load inspections
  void initialize() {
    loadInspections();
  }

  /// Load inspections from SQLite database via InspectionProvider
  Future<void> loadInspections() async {
    _isLoading = true;
    _errorMessage = null;
    notifyListeners();

    try {
      // Fetch inspections from SQLite via InspectionProvider
      final provider = db.InspectionProvider.instance;
      final dbInspections = await provider.getAllInspections();

      // Map database inspections to UI model
      _inspections = dbInspections.map((dbInspection) {
        return Inspection(
          id: dbInspection.id,
          title: 'Inspection ${dbInspection.id.substring(0, 8)}', // TODO: Add title field to database
          status: _mapStatus(dbInspection.status),
          lastModified: dbInspection.updatedAt,
          location: 'Unknown', // TODO: Add location field or join with asset/site data
          equipmentType: 'Equipment', // TODO: Add equipment type field
          progress: _calculateProgress(dbInspection.status),
        );
      }).toList();

      // Sort by last modified (most recent first)
      _inspections.sort((a, b) => b.lastModified.compareTo(a.lastModified));

    } catch (e) {
      _errorMessage = 'Failed to load inspections: ${e.toString()}';
      debugPrint('Error loading inspections: $e');
    } finally {
      _isLoading = false;
      notifyListeners();
    }
  }

  /// Map database status to UI status
  String _mapStatus(String dbStatus) {
    switch (dbStatus.toLowerCase()) {
      case 'draft':
        return 'Scheduled';
      case 'in_progress':
        return 'In Progress';
      case 'submitted':
      case 'reviewed':
        return 'Completed';
      default:
        return dbStatus;
    }
  }

  /// Calculate progress based on status
  double _calculateProgress(String status) {
    switch (status.toLowerCase()) {
      case 'draft':
        return 0.0;
      case 'in_progress':
        return 0.5;
      case 'submitted':
      case 'reviewed':
        return 1.0;
      default:
        return 0.0;
    }
  }

  /// Update search query
  void updateSearchQuery(String query) {
    _searchQuery = query;
    notifyListeners();
  }

  /// Update filter status
  void updateFilterStatus(String status) {
    _filterStatus = status;
    notifyListeners();
  }

  /// Clear search and filters
  void clearFilters() {
    _searchQuery = '';
    _filterStatus = 'All';
    notifyListeners();
  }

  /// Refresh inspections
  Future<void> refresh() async {
    await loadInspections();
  }

  /// Navigate to inspection form
  void openInspection(BuildContext context, String inspectionId) {
    // Navigate to inspection form screen (Story 3.1A schema-driven form)
    context.go(AppRoutes.inspectionFormRoute(inspectionId));
  }

  /// Get status color for UI
  Color getStatusColor(String status) {
    switch (status) {
      case 'Completed':
        return Colors.green;
      case 'In Progress':
        return Colors.blue;
      case 'Scheduled':
        return Colors.orange;
      case 'Under Review':
        return Colors.purple;
      default:
        return Colors.grey;
    }
  }

  /// Get progress color for UI
  Color getProgressColor(double progress) {
    if (progress >= 0.8) return Colors.green;
    if (progress >= 0.5) return Colors.blue;
    if (progress >= 0.3) return Colors.orange;
    return Colors.red;
  }

  /// Format last modified time for display
  String formatLastModified(DateTime dateTime) {
    final now = DateTime.now();
    final difference = now.difference(dateTime);

    if (difference.inDays > 0) {
      return '${difference.inDays}d ago';
    } else if (difference.inHours > 0) {
      return '${difference.inHours}h ago';
    } else if (difference.inMinutes > 0) {
      return '${difference.inMinutes}m ago';
    } else {
      return 'Just now';
    }
  }
}

