/// INSPECTION FORM STATE - Schema-Driven Form Management
/// ============================================================================
///
/// State management for schema-driven inspection forms.
/// Manages form data, validation, sections, and field interactions.
///
/// **OFFLINE-FIRST ARCHITECTURE:**
/// - Queries templates from LOCAL SQLite (NOT Supabase directly)
/// - Template sync happens via InspectionProvider.syncTemplatesFromSupabase()
/// - See InspectionProvider for complete offline-first architecture docs
///
/// **Data Flow:**
/// 1. User opens inspection → loadInspection(inspectionId)
/// 2. Get templateId from inspection
/// 3. Load template from SQLite (NOT Supabase) → _loadTemplateFromBackend()
/// 4. Parse template schema → SchemaParser
/// 5. Render dynamic form → DynamicWidgetFactory
/// 6. Auto-save to SQLite on field changes → InspectionProvider
///
/// ============================================================================
library;

import 'dart:async';
import 'package:flutter/material.dart';
import 'package:provider/provider.dart';
import '../../../../services/schema_parser.dart';
import '../../../../services/validation_service.dart';
import '../../../../services/conditional_logic_service.dart';
import '../../../../providers/inspection_provider.dart';
import '../../../../widgets/dynamic_widget_factory.dart';

/// State class for inspection form screen
/// Follows Provider + ChangeNotifier pattern per coding standards
class InspectionFormState extends ChangeNotifier {
  /// Current inspection ID
  String? _inspectionId;

  /// Template schema loaded from parser
  TemplateSchema? _templateSchema;

  /// Form sections loaded from schema
  List<FormSection> _sections = [];

  /// Form field values (keyed by field_id)
  Map<String, dynamic> _formData = {};

  /// Validation errors (keyed by field_id)
  final Map<String, String> _errors = {};

  /// Field UI states (visible, disabled, required)
  final Map<String, FieldUiState> _fieldUiStates = {};

  /// Loading state
  bool _isLoading = false;

  /// Collapsed sections tracking
  final Set<String> _collapsedSections = {};

  /// Selected section for quick navigation
  String? _selectedSectionId;

  /// Auto-save timer (debounced 400-600ms)
  Timer? _autoSaveTimer;

  /// Service instances
  final SchemaParser _schemaParser = SchemaParser.instance;
  final ValidationService _validationService = ValidationService.instance;
  final ConditionalLogicService _conditionalLogicService = ConditionalLogicService.instance;
  final InspectionProvider _inspectionProvider = InspectionProvider.instance;

  // Getters
  String? get inspectionId => _inspectionId;
  TemplateSchema? get templateSchema => _templateSchema;
  List<FormSection> get sections => _sections;
  Map<String, dynamic> get formData => _formData;
  Map<String, String> get errors => _errors;
  Map<String, FieldUiState> get fieldUiStates => _fieldUiStates;
  bool get isLoading => _isLoading;
  Set<String> get collapsedSections => _collapsedSections;
  String? get selectedSectionId => _selectedSectionId;

  /// Service locator pattern for accessing state from context
  static InspectionFormState s(BuildContext context, {bool listen = true}) {
    return Provider.of<InspectionFormState>(context, listen: listen);
  }

  /// Initialize form with inspection ID and schema
  /// Integrates Story 3.1A SchemaParser and InspectionProvider
  Future<void> initialize(String inspectionId) async {
    _inspectionId = inspectionId;
    _isLoading = true;
    notifyListeners();

    try {
      // Load inspection from InspectionProvider
      await _inspectionProvider.loadInspection(inspectionId);

      // Load template from LOCAL SQLite (offline-first architecture)
      // Templates are synced from Supabase → SQLite via InspectionProvider.syncTemplatesFromSupabase()
      // Query: SELECT schema_json FROM template_versions
      //        WHERE template_id = ? AND published_at IS NOT NULL
      //        ORDER BY version DESC LIMIT 1
      final templateId = _inspectionProvider.currentInspection?.templateId;
      if (templateId == null) {
        throw Exception('No template ID found for inspection');
      }

      final templateJson = await _loadTemplateFromBackend(templateId);

      // Parse schema using SchemaParser service (Story 3.1A)
      _templateSchema = await _schemaParser.parse(templateJson);

      // Convert schema sections to FormSection models
      _sections = _templateSchema!.sections.map((schemaSection) {
        return FormSection(
          id: schemaSection.id,
          title: schemaSection.title,
          displayOrder: schemaSection.displayOrder,
          fields: schemaSection.fields,
        );
      }).toList();

      // Sort sections by display order
      _sections.sort((a, b) => a.displayOrder.compareTo(b.displayOrder));

      // Load existing form data if inspection was already started
      if (_inspectionProvider.currentInspection != null) {
        _formData = Map<String, dynamic>.from(_inspectionProvider.formData);
      }

      // Initialize field UI states for all fields
      _initializeFieldUiStates();

      _isLoading = false;
      notifyListeners();
    } catch (e) {
      _isLoading = false;
      notifyListeners();
      rethrow;
    }
  }

  /// Initialize field UI states using ConditionalLogicService
  void _initializeFieldUiStates() {
    for (final section in _sections) {
      for (final field in section.fields) {
        if (field is FieldSchema) {
          // Evaluate initial UI state based on conditional rules
          final uiState = _conditionalLogicService.evaluateField(
            field,
            _formData,
          );
          _fieldUiStates[field.id] = uiState;
        }
      }
    }
  }

  /// Load template schema from local SQLite database
  /// Implements offline-first architecture: App queries ONLY SQLite (not Supabase)
  /// Templates are synced from Supabase → SQLite via sync service
  /// Queries template_versions table for the latest published version
  Future<String> _loadTemplateFromBackend(String templateId) async {
    try {
      // Get database from InspectionProvider
      // InspectionProvider manages SQLite database connection
      final database = _inspectionProvider.database;
      if (database == null) {
        throw Exception('SQLite database not initialized');
      }

      // Query local SQLite template_versions table
      // This follows offline-first pattern: UI → SQLite only
      final result = await database.query(
        'template_versions',
        columns: ['schema_json'],
        where: 'template_id = ? AND published_at IS NOT NULL',
        whereArgs: [templateId],
        orderBy: 'version DESC',
        limit: 1,
      );

      if (result.isEmpty) {
        throw Exception(
          'Template not found in local database: $templateId. '
          'Please sync templates from server first.'
        );
      }

      final schemaJson = result.first['schema_json'];
      if (schemaJson == null) {
        throw Exception('Template schema_json is null for template: $templateId');
      }

      return schemaJson as String;
    } catch (e) {
      throw Exception(
        'Failed to load template from local database. '
        'Template ID: $templateId. '
