  Future<String> capturePhoto({
    required String inspectionId,
    required String fieldId,
    String? description,
  }) async {
    if (_controller == null || !_controller!.value.isInitialized) {
      throw Exception('Camera not initialized');
    }

    // Create directory for inspection photos
    final directory = await getApplicationDocumentsDirectory();
    final inspectionDir = Directory('${directory.path}/inspections/$inspectionId/photos');

    if (!await inspectionDir.exists()) {
      await inspectionDir.create(recursive: true);
    }

    // Generate unique filename
    final timestamp = DateTime.now().millisecondsSinceEpoch;
    final filename = '${fieldId}_$timestamp.jpg';
    final filePath = join(inspectionDir.path, filename);

    // Capture image
    final XFile image = await _controller!.takePicture();

    // Move to permanent location
    final File savedImage = await File(image.path).copy(filePath);

    // Delete temporary file
    await File(image.path).delete();

    return savedImage.path;
  }

  /// Get photo dimensions
  Future<Map<String, int>> getPhotoDimensions(String filePath) async {
    final File file = File(filePath);
    if (!await file.exists()) {
      throw Exception('Photo file not found');
    }

    // For basic implementation, return standard camera dimensions
    // In production, you'd decode the image to get actual dimensions
    return {
      'width': _controller?.value.previewSize?.width.toInt() ?? 1920,
      'height': _controller?.value.previewSize?.height.toInt() ?? 1080,
    };
  }

  /// Switch between front and back cameras
  Future<void> switchCamera() async {
    if (_cameras == null || _cameras!.length < 2) return;

    final currentIndex = _cameras!.indexOf(_controller!.description);
    final newIndex = currentIndex == 0 ? 1 : 0;

    await initializeCamera(newIndex);
  }

  /// Set flash mode
  Future<void> setFlashMode(FlashMode mode) async {
    if (_controller != null && _controller!.value.isInitialized) {
      await _controller!.setFlashMode(mode);
    }
  }

  /// Get current flash mode
  FlashMode get flashMode => _controller?.value.flashMode ?? FlashMode.off;

  /// Dispose camera resources
  Future<void> dispose() async {
    await _controller?.dispose();
    _controller = null;
  }

  /// Check if camera is available
  bool get isInitialized => _controller?.value.isInitialized ?? false;

  /// Get camera controller for preview
  CameraController? get controller => _controller;

  /// Get list of photos for an inspection
  Future<List<String>> getInspectionPhotos(String inspectionId) async {
    final directory = await getApplicationDocumentsDirectory();
    final inspectionDir = Directory('${directory.path}/inspections/$inspectionId/photos');

    if (!await inspectionDir.exists()) {
      return [];
    }

    final List<FileSystemEntity> files = await inspectionDir.list().toList();
    return files
        .whereType<File>()
        .where((file) => file.path.toLowerCase().endsWith('.jpg'))
        .map((file) => file.path)
        .toList()
